create table public.courier_connections(id uuid primary key default gen_random_uuid(),seller_account_id uuid not null references public.seller_accounts(id) on delete cascade,provider text not null,credentials_encrypted text,active boolean not null default true,created_at timestamptz not null default now(),unique(seller_account_id,provider));
create table public.courier_quotes(id uuid primary key default gen_random_uuid(),seller_account_id uuid not null references public.seller_accounts(id),order_id uuid not null references public.orders(id),provider text not null,service text not null,amount_minor bigint not null,currency public.currency_code not null,provider_quote_id text,expires_at timestamptz not null,created_at timestamptz not null default now());
create table public.shipments(id uuid primary key default gen_random_uuid(),seller_account_id uuid not null references public.seller_accounts(id),order_id uuid not null references public.orders(id),provider text not null,provider_shipment_id text,tracking_number text not null,tracking_url text,label_url text,status text not null default 'booked' check(status in ('booked','in_transit','delivered','cancelled','failed')),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(order_id));
create table public.shipment_events(id uuid primary key default gen_random_uuid(),shipment_id uuid not null references public.shipments(id) on delete cascade,seller_account_id uuid not null references public.seller_accounts(id),event_key text not null unique,status text not null,payload jsonb not null default '{}',occurred_at timestamptz not null default now());
do $$declare t text;begin foreach t in array array['courier_connections','courier_quotes','shipments','shipment_events'] loop execute format('alter table public.%I enable row level security',t);execute format('alter table public.%I force row level security',t);end loop;end$$;
create policy courier_connections_owner_all on public.courier_connections for all to authenticated using(seller_account_id=(select public.current_seller_account_id())) with check(seller_account_id=(select public.current_seller_account_id()));
create policy courier_quotes_owner_all on public.courier_quotes for all to authenticated using(seller_account_id=(select public.current_seller_account_id())) with check(seller_account_id=(select public.current_seller_account_id()));
create policy shipments_owner_all on public.shipments for all to authenticated using(seller_account_id=(select public.current_seller_account_id())) with check(seller_account_id=(select public.current_seller_account_id()));
create policy shipment_events_owner_read on public.shipment_events for select to authenticated using(seller_account_id=(select public.current_seller_account_id()));
grant select,insert,update,delete on public.courier_connections,public.courier_quotes,public.shipments to authenticated;grant select on public.shipment_events to authenticated;grant all on public.courier_connections,public.courier_quotes,public.shipments,public.shipment_events to service_role;
